(window.webpackJsonp=window.webpackJsonp||[]).push([[1325],{1261:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findTilt = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> leftSum=dfs(root.left),\\n        rightSum=dfs(root.right)\\n    sum+=<span class=\\"hljs-built_in\\">Math</span>.abs(leftSum-rightSum)\\n    <span class=\\"hljs-keyword\\">return</span> leftSum+rightSum+root.val\\n  }\\n  dfs(root)\\n  <span class=\\"hljs-keyword\\">return</span> sum\\n};\\n</code></pre>\\n"],"titleSlug":"binary-tree-tilt","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u4e8c\u53c9\u6811\uff0c\u8ba1\u7b97 <strong>\u6574\u4e2a\u6811 </strong>\u7684\u5761\u5ea6 \u3002</p>\\n\\n<p>\u4e00\u4e2a\u6811\u7684<strong> \u8282\u70b9\u7684\u5761\u5ea6 </strong>\u5b9a\u4e49\u5373\u4e3a\uff0c\u8be5\u8282\u70b9\u5de6\u5b50\u6811\u7684\u8282\u70b9\u4e4b\u548c\u548c\u53f3\u5b50\u6811\u8282\u70b9\u4e4b\u548c\u7684 <strong>\u5dee\u7684\u7edd\u5bf9\u503c </strong>\u3002\u5982\u679c\u6ca1\u6709\u5de6\u5b50\u6811\u7684\u8bdd\uff0c\u5de6\u5b50\u6811\u7684\u8282\u70b9\u4e4b\u548c\u4e3a 0 \uff1b\u6ca1\u6709\u53f3\u5b50\u6811\u7684\u8bdd\u4e5f\u662f\u4e00\u6837\u3002\u7a7a\u7ed3\u70b9\u7684\u5761\u5ea6\u662f 0 \u3002</p>\\n\\n<p><strong>\u6574\u4e2a\u6811</strong> \u7684\u5761\u5ea6\u5c31\u662f\u5176\u6240\u6709\u8282\u70b9\u7684\u5761\u5ea6\u4e4b\u548c\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/20/tilt1.jpg\\" style=\\"width: 712px; height: 182px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u8282\u70b9 2 \u7684\u5761\u5ea6\uff1a|0-0| = 0\uff08\u6ca1\u6709\u5b50\u8282\u70b9\uff09\\n\u8282\u70b9 3 \u7684\u5761\u5ea6\uff1a|0-0| = 0\uff08\u6ca1\u6709\u5b50\u8282\u70b9\uff09\\n\u8282\u70b9 1 \u7684\u5761\u5ea6\uff1a|2-3| = 1\uff08\u5de6\u5b50\u6811\u5c31\u662f\u5de6\u5b50\u8282\u70b9\uff0c\u6240\u4ee5\u548c\u662f 2 \uff1b\u53f3\u5b50\u6811\u5c31\u662f\u53f3\u5b50\u8282\u70b9\uff0c\u6240\u4ee5\u548c\u662f 3 \uff09\\n\u5761\u5ea6\u603b\u548c\uff1a0 + 0 + 1 = 1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/20/tilt2.jpg\\" style=\\"width: 800px; height: 203px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [4,2,9,3,5,null,7]\\n<strong>\u8f93\u51fa\uff1a</strong>15\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u8282\u70b9 3 \u7684\u5761\u5ea6\uff1a|0-0| = 0\uff08\u6ca1\u6709\u5b50\u8282\u70b9\uff09\\n\u8282\u70b9 5 \u7684\u5761\u5ea6\uff1a|0-0| = 0\uff08\u6ca1\u6709\u5b50\u8282\u70b9\uff09\\n\u8282\u70b9 7 \u7684\u5761\u5ea6\uff1a|0-0| = 0\uff08\u6ca1\u6709\u5b50\u8282\u70b9\uff09\\n\u8282\u70b9 2 \u7684\u5761\u5ea6\uff1a|3-5| = 2\uff08\u5de6\u5b50\u6811\u5c31\u662f\u5de6\u5b50\u8282\u70b9\uff0c\u6240\u4ee5\u548c\u662f 3 \uff1b\u53f3\u5b50\u6811\u5c31\u662f\u53f3\u5b50\u8282\u70b9\uff0c\u6240\u4ee5\u548c\u662f 5 \uff09\\n\u8282\u70b9 9 \u7684\u5761\u5ea6\uff1a|0-7| = 7\uff08\u6ca1\u6709\u5de6\u5b50\u6811\uff0c\u6240\u4ee5\u548c\u662f 0 \uff1b\u53f3\u5b50\u6811\u6b63\u597d\u662f\u53f3\u5b50\u8282\u70b9\uff0c\u6240\u4ee5\u548c\u662f 7 \uff09\\n\u8282\u70b9 4 \u7684\u5761\u5ea6\uff1a|(3+5+2)-(9+7)| = |10-16| = 6\uff08\u5de6\u5b50\u6811\u503c\u4e3a 3\u30015 \u548c 2 \uff0c\u548c\u662f 10 \uff1b\u53f3\u5b50\u6811\u503c\u4e3a 9 \u548c 7 \uff0c\u548c\u662f 16 \uff09\\n\u5761\u5ea6\u603b\u548c\uff1a0 + 0 + 0 + 2 + 7 + 6 = 15\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/20/tilt3.jpg\\" style=\\"width: 800px; height: 293px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [21,7,14,1,1,2,2,3,3]\\n<strong>\u8f93\u51fa\uff1a</strong>9\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u8282\u70b9\u6570\u76ee\u7684\u8303\u56f4\u5728 <code>[0, 10<sup>4</sup>]</code> \u5185</li>\\n\\t<li><code>-1000 <= Node.val <= 1000</code></li>\\n</ul>\\n","title":"563. \u4e8c\u53c9\u6811\u7684\u5761\u5ea6","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22","\u9012\u5f52"],"difficult":"Easy","lang":["javascript"],"uniqueID":"563"}')}}]);